install_pacman_package wget # retrieves files from the web
install_pacman_package xsel # command line tool to access X clipboard and selection buffers
install_pacman_package zoxide # Shell extension to easily jump to frequently accessed directories

# Diagnostics
install_pacman_package atop # Monitor for system resources and process activity
install_pacman_package htop # interactive processes viewer
install_pacman_package iftop # displays bandwidth usage information on an network interface
install_pacman_package iotop # simple top-like I/O monitor
install_pacman_package lsof # Utility to list open files
install_pacman_package ltrace # Tracks runtime library calls in dynamically linked programs
install_pacman_package nethogs # Net top tool grouping bandwidth per process
install_pacman_package strace # System call tracer

# Packages (arch-specific):

install_pacman_package fd # Simple, fast and user-friendly alternative to find
install_pacman_package git-delta # Syntax-highlighting pager for git and diff output
install_pacman_package lazydocker # terminal ui for docker and docker-compose
install_pacman_package lazygit # terminal ui for git
install_pacman_package starship # shell-agnostic prompt
install_pacman_package the_silver_searcher # very fast grep-like program, alternative to ack-grep
